@startuml
skinparam shadowing false
skinparam packageStyle rectangle
skinparam classAttributeIconSize 0

package "LoggingOgSporing" {
  class "Endringslogg" as Endringslogg {
  }

  class "Hendelseslogg" as Hendelseslogg {
    + hendelsetype : Hendelsetype
    + beskrivelse : string [0..1]
    + hendelseDato : datetime
  }

  note right of Hendelseslogg
  <i>Endringslogg:</i>
  end note

  Hendelseslogg -|> Endringslogg
}
@enduml
